import org.apache.commons.math3.util.FastMath;

public class VerifyFix {
    public static void main(String[] args) {
        double x = 710.0;

        System.out.println("Testing FastMath.cosh and FastMath.sinh for x = " + x);
        System.out.println("FastMath.cosh(710.0) = " + FastMath.cosh(710.0));
        System.out.println("FastMath.sinh(710.0) = " + FastMath.sinh(710.0));
        System.out.println("Math.cosh(710.0) = " + Math.cosh(710.0));
        System.out.println("Math.sinh(710.0) = " + Math.sinh(710.0));

        // Check if results are finite
        System.out.println("FastMath.cosh(710.0) is finite: " + Double.isFinite(FastMath.cosh(710.0)));
        System.out.println("FastMath.sinh(710.0) is finite: " + Double.isFinite(FastMath.sinh(710.0)));

        // Check approximate values
        double expected = 1.1169973830808557E308;
        double coshResult = FastMath.cosh(710.0);
        double sinhResult = FastMath.sinh(710.0);

        System.out.println("Expected: " + expected);
        System.out.println("cosh Result: " + coshResult);
        System.out.println("sinh Result: " + sinhResult);
        System.out.println("cosh Difference (relative): " + Math.abs((coshResult - expected) / expected));
        System.out.println("sinh Difference (relative): " + Math.abs((sinhResult - expected) / expected));

        // Test ULP distance
        System.out.println("cosh ULP distance from Math.cosh: " + Math.ulp(coshResult));
        System.out.println("sinh ULP distance from Math.sinh: " + Math.ulp(sinhResult));
        System.out.println("Difference from Math.cosh: " + Math.abs(coshResult - Math.cosh(710.0)));
        System.out.println("Difference from Math.sinh: " + Math.abs(sinhResult - Math.sinh(710.0)));
    }
}

